var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……크르르르윽!","JPN":"……グルルル！","ENG":"...Grrrrgh!","TWN":"……咕呃呃呃呃！"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 끝입니다. 하베스터.","JPN":"これで終わりです、ハーベスター。","ENG":"This ends here, Harvester.","TWN":"就此結束吧，收割者。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"커억……!","JPN":"ガハッ……！","ENG":"Graah...!","TWN":"呃……！"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어때요, 분한가요?","JPN":"どうですか？　悔しいでしょう？","ENG":"How do you feel? Angry?","TWN":"怎麼樣，氣憤嗎？"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무리 날뛰어 봤자, 당신은 아직 저와 같은 무대에 설 수 없어요.","JPN":"どれだけ足掻こうと、あなたはまだ私と同じ舞台には立てません。","ENG":"No matter how hard you try, you will never stand on the same stage as me.","TWN":"無論怎麼掙扎，你還無法站在和我同樣的舞台上。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 기억하도록 하세요.","JPN":"だから覚えておきなさい。","ENG":"So let this moment sink in.","TWN":"所以請記住吧。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 감정을, 치욕을, 종으로서 열등함을……. 밑 바닥 없는 절망의 끝을.","JPN":"その感情を、屈辱を、種の劣等感を……底知れない絶望の果てを。","ENG":"Your emotion, your shame, and your inferiority as a species... The end of a bottomless despair.","TWN":"那種情緒，那種恥辱，作為一個物種的劣等感……無盡的絕望的盡頭。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……크윽.","JPN":"……くうっ。","ENG":"...Kgh.","TWN":"……科科。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"크하아아아아악──!!","JPN":"クアアアアアアアーー！！","ENG":"KRAAAAAAGH!!","TWN":"嘎啊啊啊啊啊──！！"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"또 죽음으로 다른 개체에게 정보를 넘길 셈이로군요.","JPN":"また、死ぬことによって別の個体に情報を渡そうとしてますね。","ENG":"Again, passing information to another of your kind upon death.","TWN":"又一次，想透過死亡將資訊傳遞給其他個體嗎？"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 죽지 않는다면, 무가치한 일이겠죠.","JPN":"でも死ねないなら意味のないこと。","ENG":"But if you don't die, it will be a worthless attempt.","TWN":"但如果死不了，那就毫無意義了吧。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……여긴. 어디?","JPN":"……ココハ、ドコダ？","ENG":"...Where. Is this?","TWN":"……這是。哪？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그곳은 제 거울 속. <color=#ffd34c>파노라마</color>의 세계.","JPN":"そこは私の鏡の中。<color=#ffd34c>パノラマ</color>の世界。","ENG":"This is within my mirror. The world of <color=#ffd34c>Panorama</color>.","TWN":"你在我的鏡子裡。<color=#ffd34c>全景</color>的世界裡。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마왕</color>과 계약하여 얻은, 잊혀진 세계의 편린이죠.","JPN":"<color=#ffd34c>魔王</color>との契約で手に入れた、忘れられた世界の片鱗です。","ENG":"It's a piece of the forgotten world that I obtained through a contract with <color=#ffd34c>the Demon Lord</color>.","TWN":"這是與<color=#ffd34c>魔王</color>簽訂契約後獲得的，遺忘世界的碎片。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……이곳.","JPN":"……ココ。","ENG":"...This place.","TWN":"……這裡。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"알고 있다. 멸망한.","JPN":"知ッテイル。滅ビタ。","ENG":"I know. Destroyed.","TWN":"滅亡的。味道。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"그르르르……!","JPN":"グルルル……！","ENG":"Grrr...!","TWN":"嗚喔喔喔……！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"……저건?","JPN":"……アレハ？","ENG":"...That's?","TWN":"……那是？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"동족?","JPN":"同族？","ENG":"My kind?","TWN":"我的同類？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 그건 당신에게서 비춰진 거울상.","JPN":"そうです。あれは鏡に映ったあなた。","ENG":"Yes. That is a reflection of you.","TWN":"是的，那是從你身上反射出來的鏡像。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시간과 공간마저 단절된 그곳에서 당신은 완전히 똑같은 자신과 충돌하게 될 겁니다.","JPN":"時間と空間すら断絶されたその場所で、あなたはもう一人の自分とぶつかることになるでしょう。","ENG":"With time and space cut off from the world, you will face an exact version of yourself.","TWN":"在這個時間和空間都被切斷的地方，你將會與完全相同的自己相遇。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 걸 포기하고, 저에게 완벽히 굴복하게 될 때까지.","JPN":"すべてを諦め、私に屈服するまで。","ENG":"Until you give up everything and completely submit to me.","TWN":"放棄一切吧，直到你完全屈服於我。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"크하아아악! 죽어!","JPN":"クアアアア！　死ネ！","ENG":"Graaa! Die!","TWN":"啊啊啊啊啊！死！"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"죽여버리겠다!","JPN":"殺シテヤル！","ENG":"I KILL YOU!","TWN":"殺了！你！"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};